parameters.jsonBody:
={
  "urls": ["{{ $json.url }}"],
  "prompt": "Extract the primary contact and company info from this page. If it's a directory listing of multiple companies, return the FIRST company only — we'll call you again for the others. Use empty string for any field you can't confidently fill. Always try to capture at least ONE contactable channel (email, phone, or a social profile URL) — leads with only social/phone are still useful, we reach out to them manually.",
  "schema": {
    "type": "object",
    "properties": {
      "company":   { "type": "string", "description": "Business / organization name" },
      "name":      { "type": "string", "description": "Primary contact person name; empty string if no person is listed (don't invent one)" },
      "email":     { "type": "string", "description": "Best public contact email; empty string if none" },
      "phone":     { "type": "string", "description": "Phone in international format if shown; empty string if none" },
      "website":   { "type": "string", "description": "Official website URL; empty string if not the source page" },
      "facebook":  { "type": "string", "description": "Facebook page URL; empty string if none" },
      "instagram": { "type": "string", "description": "Instagram URL; empty string if none" },
      "linkedin":  { "type": "string", "description": "LinkedIn company / profile URL; empty string if none" },
      "category":  { "type": "string", "description": "Industry / niche this company operates in (keep under 100 chars; pick ONE primary niche, don't list multiple)" },
      "location":  { "type": "string", "description": "City + country if shown" },
      "summary":   { "type": "string", "description": "One-line summary of what this company does" }
    },
    "required": ["company"]
  }
}

